import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F06_存貨與債務穩定度審計_財務分析專家.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F06_存貨與債務穩定度審計_財務分析專家.md"}'),l={name:"審計報告庫/財務審計/6903_巨漢/20260502/F06_存貨與債務穩定度審計_財務分析專家.md"};function o(n,a,_,s,h,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢屬輕資產工程服務業，存貨極低（&lt;0.5% 總資產），無存貨跌價風險。流動性極佳——帳上現金約 17-22 億，幾乎無銀行借款，流動比率 &gt;300%，速動比率 &gt;280%，償債能力無虞。唯一隱憂是 DSO 攀升至 130 天，應收帳款佔流動資產比重提高。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（優）。現金充沛、無銀行借款、流動比率 &gt;300%，財務體質健康。利空：2025 年 DSO 130 天偏高，應收帳款 11.29 億佔流動資產約 35%，若客戶延遲付款將壓縮現金運用效率，收款風險不可輕忽。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>存貨分析</strong>：巨漢為工程統包公司，存貨僅為零星物料（2025 年 1,614 萬），存貨週轉天數 5 天，遠低於製造業平均。無存貨堆積或跌價損失風險。</p></li><li><p><strong>流動性分析</strong>：2025 年流動資產約 32-35 億，其中現金約 17-22 億（佔比 ~60%）。流動負債約 10-12 億（主要為合約負債 + 應付帳款）。流動比率 &gt;300%，速動比率 &gt;280%。無短期借款、無長期借款、無應付公司債，公司幾乎是零負債經營。</p></li><li><p><strong>營運週期</strong>：現金循環天數約 135 天，主要受 DSO 130 天驅動。由於公司無借款，營運資金完全來自自有現金和客戶預付款（合約負債），資金成本低但資金運用效率有待提升。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>現金過剩的雙面刃</strong>：帳上現金 17-22 億遠超過營運需求（月營收約 2.65 億，6 個月營運資金約 16 億即足）。多餘現金僅做定存（利息收入約 1,500-2,000 萬/年，收益率 &lt;1%），資金運用效率低落。</li><li><strong>應收帳款集中風險</strong>：2025 年 AR 暴增 236% 至 11.29 億，雖部分為時間差，但若集中在某一客戶，一旦發生延遲付款或壞帳，將一次性侵蝕大量現金。需查閱年報 AR 明細。</li><li><strong>無借款的利與弊</strong>：零負債雖安全，但也意味著公司未運用財務槓桿提升 ROE。目前 ROE 約 15-18%，若有適度借款（負債比 30%），ROE 可望提升至 20%+。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>財務分析工具.py：inventory_check 6903</li><li>FinMind：TaiwanStockBalanceSheet（CashAndCashEquivalents, CurrentAssets, CurrentLiabilities）</li></ul>',12)])])}const u=t(l,[["render",o]]);export{p as __pageData,u as default};
